import { Avatar, Card, CardContent, CardHeader, Divider, IconButton, Typography} from '@material-ui/core'
import { MoreVert} from '@material-ui/icons'
import React from 'react'

export default function SubjectCards({ subject }) {
  return (
    <div>
        <Card elevation={1}>
            <CardHeader
            avatar={
              <Avatar color='secondary'>
                P
              </Avatar>
            }
              action={
                <IconButton>
                  <MoreVert/>
                </IconButton>
              }
              title = {subject.title}
              subheader = {subject.instructor}
            />
            <Divider />
            <CardContent>
              <Typography>
                {subject.body}
              </Typography>
            </CardContent>
        </Card>
    </div>
  )
}
